@namespace sv_1a0f94f8ff13467691717380f24530b8.Components.Pages.Settings
@using sv_1a0f94f8ff13467691717380f24530b8.Services

<div class="profile-section">
    <h4>Profile Settings</h4>

    @if (Profile is not null)
    {
        <div class="avatar-area mb-4">
            <div class="avatar-preview">
                <img src="@editDisplayName" alt="avatar" onerror="this.style.display='none'" />
                <div class="avatar-placeholder">👤</div>
            </div>
            <div class="avatar-url-display">
                <small class="text-muted">Avatar URL:</small>
                <span class="text-truncate d-block">@editAvatarUrl</span>
            </div>
        </div>

        <div class="mb-3">
            <label class="form-label">Display Name</label>
            <input type="text" class="form-control" @bind="editDisplayName" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email</label>
            <input type="email" class="form-control" @bind="editEmail" />
        </div>

        <div class="mb-3">
            <label class="form-label">Avatar URL</label>
            <input type="url" class="form-control" @bind="editAvatarUrl" />
        </div>

        <div class="mb-3">
            <label class="form-label">Bio</label>
            <textarea class="form-control" rows="4" @bind="editBio"></textarea>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
                @(isSaving ? "Saving…" : "Save Changes")
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@isSaving">
                Discard Changes
            </button>
        </div>

        @if (showSuccess)
        {
            <div class="alert alert-success mt-3 fade-in" role="alert">
                ✅ Profile saved successfully!
            </div>
        }
    }
    else
    {
        <p class="text-muted">Loading profile…</p>
    }
</div>

@code {
    [Parameter, EditorRequired] public UserProfile? Profile { get; set; }
    [Parameter, EditorRequired] public EventCallback<UserProfile> OnSave { get; set; }

    private string editDisplayName = "";
    private string editEmail = "";
    private string editAvatarUrl = "";
    private string editBio = "";
    private bool isSaving;
    private bool showSuccess;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !isDirty)
        {
            ResetFields();
        }
    }

    private bool isDirty =>
        Profile is not null && (
            editDisplayName != Profile.DisplayName ||
            editEmail != Profile.Email ||
            editAvatarUrl != Profile.AvatarUrl ||
            editBio != Profile.Bio);

    private void ResetFields()
    {
        if (Profile is null) return;
        editDisplayName = Profile.DisplayName;
        editEmail = Profile.Email;
        editAvatarUrl = Profile.AvatarUrl;
        editBio = Profile.Bio;
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        showSuccess = false;
        var updated = new UserProfile(editDisplayName, editEmail, editAvatarUrl, editBio);
        await OnSave.InvokeAsync(updated);
        isSaving = false;
        showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void Discard() => ResetFields();
}

.profile-section {
    max-width: 600px;
}

.avatar-area {
    display: flex;
    align-items: center;
    gap: 1rem;
}

.avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    overflow: hidden;
    background: #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    border: 2px solid #dee2e6;
}

.avatar-preview img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 2rem;
}

.avatar-url-display {
    min-width: 0;
    flex: 1;
}

.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

@namespace sv_1a0f94f8ff13467691717380f24530b8.Components.Pages.Settings
@using sv_1a0f94f8ff13467691717380f24530b8.Services

<div class="notifications-section">
    <h4>Notification Preferences</h4>

    @if (Prefs is not null)
    {
        <div class="mb-4">
            <h6>General</h6>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif"
                       checked="@emailNotifications" @onchange="e => emailNotifications = (bool)e.Value!" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif"
                       checked="@pushNotifications" @onchange="e => pushNotifications = (bool)e.Value!" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest"
                       checked="@weeklyDigest" @onchange="e => weeklyDigest = (bool)e.Value!" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <div class="mb-4">
            <h6>Muted Channels</h6>
            @if (AllChannels.Count > 0)
            {
                @foreach (var channel in AllChannels)
                {
                    <div class="form-check mb-1">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@mutedChannels.Contains(channel)"
                               @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            }
            else
            {
                <p class="text-muted">No channels available.</p>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
            @(isSaving ? "Saving…" : "Save Preferences")
        </button>

        @if (showSuccess)
        {
            <div class="alert alert-success mt-3 fade-in" role="alert">
                ✅ Notification preferences saved!
            </div>
        }
    }
    else
    {
        <p class="text-muted">Loading notification preferences…</p>
    }
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs? Prefs { get; set; }
    [Parameter, EditorRequired] public List<string> AllChannels { get; set; } = [];
    [Parameter, EditorRequired] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = [];
    private bool isSaving;
    private bool showSuccess;
    private bool initialized;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !initialized)
        {
            emailNotifications = Prefs.EmailNotifications;
            pushNotifications = Prefs.PushNotifications;
            weeklyDigest = Prefs.WeeklyDigest;
            mutedChannels = [.. Prefs.MutedChannels];
            initialized = true;
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        showSuccess = false;
        var updated = new NotificationPrefs(emailNotifications, pushNotifications, weeklyDigest, [.. mutedChannels]);
        await OnSave.InvokeAsync(updated);
        isSaving = false;
        showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

.notifications-section {
    max-width: 600px;
}

.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

