arguments.file_text:
@namespace sv_1a0f94f8ff13467691717380f24530b8.Components.Pages.Settings

<div class="change-password-panel">
    <button class="btn btn-outline-secondary d-flex align-items-center gap-2"
            @onclick="() => isExpanded = !isExpanded">
        <span class="expand-icon">@(isExpanded ? "▼" : "▶")</span>
        Change Password
    </button>

    @if (isExpanded)
    {
        <div class="password-form mt-3">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(errorMessage))
            {
                <div class="alert alert-danger" role="alert">@errorMessage</div>
            }
            @if (showSuccess)
            {
                <div class="alert alert-success fade-in" role="alert">✅ Password updated!</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@isUpdating">
                @(isUpdating ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private bool isExpanded;
    private bool isUpdating;
    private string? errorMessage;
    private bool showSuccess;

    private async Task UpdatePasswordAsync()
    {
        errorMessage = null;
        showSuccess = false;

        if (string.IsNullOrWhiteSpace(currentPassword) || string.IsNullOrWhiteSpace(newPassword))
        {
            errorMessage = "All password fields are required.";
            return;
        }
        if (newPassword != confirmPassword)
        {
            errorMessage = "New password and confirmation do not match.";
            return;
        }
        if (newPassword.Length < 8)
        {
            errorMessage = "New password must be at least 8 characters.";
            return;
        }

        isUpdating = true;
        try
        {
            await OnChangePassword.InvokeAsync((currentPassword, newPassword));
            showSuccess = true;
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
            _ = HideSuccessAfterDelay();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isUpdating = false;
        }
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

.change-password-panel {
    margin-bottom: 1.5rem;
}

.password-form {
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 0.5rem;
    border: 1px solid #dee2e6;
    max-width: 400px;
}

.expand-icon {
    font-size: 0.75rem;
}

.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

@namespace sv_1a0f94f8ff13467691717380f24530b8.Components.Pages.Settings
@using sv_1a0f94f8ff13467691717380f24530b8.Services

<div class="active-sessions-table">
    <h6>Active Sessions</h6>
    @if (Sessions is { Count: > 0 })
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td>
                                @if (session.Id != CurrentSessionId)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => RequestRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
    else
    {
        <p class="text-muted">No active sessions.</p>
    }
</div>

@if (sessionToRevoke is not null)
{
    <RevokeSessionDialog Session="sessionToRevoke"
                         OnConfirm="ConfirmRevoke"
                         OnCancel="CancelRevoke" />
}

@code {
    [Parameter, EditorRequired] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public string? CurrentSessionId { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? sessionToRevoke;

    private void RequestRevoke(ActiveSession session) => sessionToRevoke = session;
    private void CancelRevoke() => sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (sessionToRevoke is not null)
        {
            await OnRevoke.InvokeAsync(sessionToRevoke.Id);
            sessionToRevoke = null;
        }
    }
}

.active-sessions-table {
    margin-top: 1.5rem;
}

@namespace sv_1a0f94f8ff13467691717380f24530b8.Components.Pages.Settings
@using sv_1a0f94f8ff13467691717380f24530b8.Services

<div class="dialog-backdrop" @onclick="OnCancel">
    <div class="dialog-content" @onclick:stopPropagation="true">
        <h5>Revoke Session</h5>
        <p>
            Are you sure you want to revoke the session on
            <strong>@Session.Device</strong> in <strong>@Session.Location</strong>?
        </p>
        <p class="text-muted small">This will sign out that device immediately.</p>
        <div class="d-flex gap-2 justify-content-end">
            <button class="btn btn-outline-secondary" @onclick="OnCancel">Cancel</button>
            <button class="btn btn-danger" @onclick="OnConfirm">Revoke</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ActiveSession Session { get; set; } = default!;
