@namespace sv_1a0f94f8ff13467691717380f24530b8.Components.Pages.Settings
@using sv_1a0f94f8ff13467691717380f24530b8.Services

<div class="active-sessions-table">
    <h6>Active Sessions</h6>
    @if (Sessions is { Count: > 0 })
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td>
                                @if (session.Id != CurrentSessionId)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => RequestRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
    else
    {
        <p class="text-muted">No active sessions.</p>
    }
</div>

@if (sessionToRevoke is not null)
{
    <RevokeSessionDialog Session="sessionToRevoke"
                         OnConfirm="ConfirmRevoke"
                         OnCancel="CancelRevoke" />
}

@code {
    [Parameter, EditorRequired] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public string? CurrentSessionId { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? sessionToRevoke;

    private void RequestRevoke(ActiveSession session) => sessionToRevoke = session;
    private void CancelRevoke() => sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (sessionToRevoke is not null)
        {
            await OnRevoke.InvokeAsync(sessionToRevoke.Id);
            sessionToRevoke = null;
        }
    }
}

