@namespace sv_1a0f94f8ff13467691717380f24530b8.Components.Pages.Settings
@using sv_1a0f94f8ff13467691717380f24530b8.Services

<div class="security-section">
    <h4>Security</h4>

    @if (SecurityData is not null)
    {
        <ChangePasswordPanel OnChangePassword="OnChangePassword" />

        <div class="tfa-section mb-4">
            <h6>Two-Factor Authentication</h6>
            <div class="d-flex align-items-center gap-3">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="tfa"
                           checked="@SecurityData.TwoFactorEnabled" disabled />
                    <label class="form-check-label" for="tfa">
                        @(SecurityData.TwoFactorEnabled ? "Enabled" : "Disabled")
                    </label>
                </div>
                <span class="badge @(SecurityData.TwoFactorEnabled ? "bg-success" : "bg-warning text-dark")">
                    @(SecurityData.TwoFactorEnabled ? "✓ Active" : "⚠ Inactive")
                </span>
            </div>
            @if (SecurityData.LastPasswordChange.HasValue)
            {
                <small class="text-muted d-block mt-2">
                    Last password change: @SecurityData.LastPasswordChange.Value.ToString("MMMM d, yyyy")
                </small>
            }
        </div>

        <ActiveSessionsTable Sessions="SecurityData.Sessions"
                             CurrentSessionId="@SecurityData.Sessions.FirstOrDefault()?.Id"
                             OnRevoke="OnRevokeSession" />
    }
    else
    {
        <p class="text-muted">Loading security settings…</p>
    }
</div>

@code {
    [Parameter, EditorRequired] public SecuritySettings? SecurityData { get; set; }
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnRevokeSession { get; set; }
}

.security-section {
    max-width: 700px;
}

.tfa-section {
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 0.5rem;
    border: 1px solid #dee2e6;
}

@namespace sv_1a0f94f8ff13467691717380f24530b8.Components.Pages.Settings
@using sv_1a0f94f8ff13467691717380f24530b8.Services

<div class="appearance-section">
    <h4>Appearance</h4>

    @if (Settings is not null)
    {
        <div class="row">
            <div class="col-md-7">
                <div class="mb-4">
                    <h6>Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")"
                                   value="@theme"
                                   checked="@(selectedTheme == theme)"
                                   @onchange="() => selectedTheme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h6>Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"font-{size}")"
                                   value="@size"
                                   checked="@(selectedFontSize == size)"
                                   @onchange="() => selectedFontSize = size" />
                            <label class="form-check-label" for="@($"font-{size}")">@size</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h6>Language</h6>
                    <select class="form-select" style="max-width: 250px;"
                            @bind="selectedLanguage">
                        @foreach (var lang in Languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               checked="@compactMode" @onchange="e => compactMode = (bool)e.Value!" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
                    @(isSaving ? "Saving…" : "Save")
                </button>

                @if (showSuccess)
                {
                    <div class="alert alert-success mt-3 fade-in" role="alert">
                        ✅ Appearance settings saved!
                    </div>
                }
            </div>

            <div class="col-md-5">
                <h6>Live Preview</h6>
                <div class="preview-area @PreviewThemeClass" style="font-size: @PreviewFontSize;">
                    <div class="preview-header">
                        <strong>Preview</strong>
                        <span class="preview-badge">@selectedTheme</span>
                    </div>
                    <div class="preview-body" style="@(compactMode ? "padding: 0.5rem;" : "padding: 1rem;")">
                        <p class="mb-1">This is how your content will look.</p>
                        <p class="mb-1 text-muted-preview">Secondary text appears like this.</p>
                        <button class="preview-btn">Sample Button</button>
                    </div>
                    <div class="preview-footer">
                        @selectedLanguage · @selectedFontSize · @(compactMode ? "Compact" : "Normal")
                    </div>
                </div>
            </div>
        </div>
    }
    else
    {
        <p class="text-muted">Loading appearance settings…</p>
    }
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings? Settings { get; set; }
    [Parameter, EditorRequired] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string selectedTheme = "Light";
    private string selectedFontSize = "Medium";
    private string selectedLanguage = "English";
    private bool compactMode;
    private bool isSaving;
    private bool showSuccess;
    private bool initialized;

    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    protected override void OnParametersSet()
    {
        if (Settings is not null && !initialized)
        {
            selectedTheme = Settings.Theme;
            selectedFontSize = Settings.FontSize;
            selectedLanguage = Settings.Language;
            compactMode = Settings.CompactMode;
            initialized = true;
        }
    }

    private string PreviewThemeClass => selectedTheme switch
    {
        "Dark" => "preview-dark",
        "System" => "preview-system",
        _ => "preview-light"
    };

    private string PreviewFontSize => selectedFontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    private async Task SaveAsync()
    {
        isSaving = true;
        showSuccess = false;
        var updated = new AppearanceSettings(selectedTheme, selectedFontSize, selectedLanguage, compactMode);
        await OnSave.InvokeAsync(updated);
        isSaving = false;
        showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

.appearance-section {
    max-width: 800px;
}

.preview-area {
    border-radius: 0.5rem;
    border: 1px solid #dee2e6;
    overflow: hidden;
    transition: all 0.2s ease;
}

.preview-header {
    padding: 0.75rem 1rem;
    display: flex;
    justify-content: space-between;
    align-items: center;
    border-bottom: 1px solid inherit;
}

.preview-badge {
    font-size: 0.75rem;
    padding: 0.15rem 0.5rem;
    border-radius: 1rem;
}

.preview-body {
    transition: padding 0.2s ease;
}

.preview-footer {
    padding: 0.5rem 1rem;
    font-size: 0.8rem;
    border-top: 1px solid inherit;
}

.preview-btn {
    padding: 0.35rem 0.75rem;
    border-radius: 0.25rem;
    border: none;
    cursor: default;
    font-size: inherit;
}

/* Light theme */
.preview-light {
    background: #ffffff;
    color: #212529;
    border-color: #dee2e6;
}
.preview-light .preview-header {
    background: #f8f9fa;
    border-color: #dee2e6;
}
.preview-light .preview-footer {
    background: #f8f9fa;
    color: #6c757d;
    border-color: #dee2e6;
}
.preview-light .preview-badge {
    background: #e9ecef;
    color: #495057;
}
.preview-light .text-muted-preview {
    color: #6c757d;
}
.preview-light .preview-btn {
    background: #0d6efd;
    color: #fff;
}

/* Dark theme */
.preview-dark {
    background: #1e1e1e;
    color: #e0e0e0;
    border-color: #444;
}
.preview-dark .preview-header {
    background: #2d2d2d;
    border-color: #444;
}
.preview-dark .preview-footer {
    background: #2d2d2d;
    color: #999;
    border-color: #444;
}
.preview-dark .preview-badge {
    background: #444;
    color: #ccc;
}
.preview-dark .text-muted-preview {
    color: #999;
}
.preview-dark .preview-btn {
    background: #4a9eff;
    color: #1e1e1e;
}

/* System theme */
.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e1e 50%);
    color: #212529;
    border-color: #aaa;
}
.preview-system .preview-header {
    background: #e9ecef;
    border-color: #aaa;
}
.preview-system .preview-footer {
    background: #e9ecef;
    color: #6c757d;
    border-color: #aaa;
}
.preview-system .preview-badge {
    background: #d0d0d0;
    color: #495057;
}
.preview-system .text-muted-preview {
    color: #6c757d;
}
.preview-system .preview-btn {
    background: #0d6efd;
    color: #fff;
}

.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

