@code {
    [Parameter, EditorRequired] public AppearanceSettings? Settings { get; set; }
    [Parameter, EditorRequired] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string selectedTheme = "Light";
    private string selectedFontSize = "Medium";
    private string selectedLanguage = "English";
    private bool compactMode;
    private bool isSaving;
    private bool showSuccess;
    private bool initialized;

    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    protected override void OnParametersSet()
    {
        if (Settings is not null && !initialized)
        {
            selectedTheme = Settings.Theme;
            selectedFontSize = Settings.FontSize;
            selectedLanguage = Settings.Language;
            compactMode = Settings.CompactMode;
            initialized = true;
        }
    }

    private string PreviewThemeClass => selectedTheme switch
    {
        "Dark" => "preview-dark",
        "System" => "preview-system",
        _ => "preview-light"
    };

    private string PreviewFontSize => selectedFontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    private async Task SaveAsync()
    {
        isSaving = true;
        showSuccess = false;
        var updated = new AppearanceSettings(selectedTheme, selectedFontSize, selectedLanguage, compactMode);
        await OnSave.InvokeAsync(updated);
        isSaving = false;
        showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

