toolArgs.file_text:
.appearance-section {
    max-width: 800px;
}

.preview-area {
    border-radius: 0.5rem;
    border: 1px solid #dee2e6;
    overflow: hidden;
    transition: all 0.2s ease;
}

.preview-header {
    padding: 0.75rem 1rem;
    display: flex;
    justify-content: space-between;
    align-items: center;
    border-bottom: 1px solid inherit;
}

.preview-badge {
    font-size: 0.75rem;
    padding: 0.15rem 0.5rem;
    border-radius: 1rem;
}

.preview-body {
    transition: padding 0.2s ease;
}

.preview-footer {
    padding: 0.5rem 1rem;
    font-size: 0.8rem;
    border-top: 1px solid inherit;
}

.preview-btn {
    padding: 0.35rem 0.75rem;
    border-radius: 0.25rem;
    border: none;
    cursor: default;
    font-size: inherit;
}

/* Light theme */
.preview-light {
    background: #ffffff;
    color: #212529;
    border-color: #dee2e6;
}
.preview-light .preview-header {
    background: #f8f9fa;
    border-color: #dee2e6;
}
.preview-light .preview-footer {
    background: #f8f9fa;
    color: #6c757d;
    border-color: #dee2e6;
}
.preview-light .preview-badge {
    background: #e9ecef;
    color: #495057;
}
.preview-light .text-muted-preview {
    color: #6c757d;
}
.preview-light .preview-btn {
    background: #0d6efd;
    color: #fff;
}

/* Dark theme */
.preview-dark {
    background: #1e1e1e;
    color: #e0e0e0;
    border-color: #444;
}
.preview-dark .preview-header {
    background: #2d2d2d;
    border-color: #444;
}
.preview-dark .preview-footer {
    background: #2d2d2d;
    color: #999;
    border-color: #444;
}
.preview-dark .preview-badge {
    background: #444;
    color: #ccc;
}
.preview-dark .text-muted-preview {
    color: #999;
}
.preview-dark .preview-btn {
    background: #4a9eff;
    color: #1e1e1e;
}

/* System theme */
.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e1e 50%);
    color: #212529;
    border-color: #aaa;
}
.preview-system .preview-header {
    background: #e9ecef;
    border-color: #aaa;
}
.preview-system .preview-footer {
    background: #e9ecef;
    color: #6c757d;
    border-color: #aaa;
}
.preview-system .preview-badge {
    background: #d0d0d0;
    color: #495057;
}
.preview-system .text-muted-preview {
    color: #6c757d;
}
.preview-system .preview-btn {
    background: #0d6efd;
    color: #fff;
}

.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

